using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap the Open-Meteo REST API.
/// HttpClient is constructor-injected via the DI container.
/// </summary>
[McpServerToolType]
public class WeatherApiTools(HttpClient httpClient, ILogger<WeatherApiTools> logger)
{
    [McpServerTool, Description("Get the current weather for a location given its latitude and longitude.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location (e.g. 47.6062)")] double latitude,
        [Description("Longitude of the location (e.g. -122.3321)")] double longitude,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching weather for ({Lat}, {Lon})", latitude, longitude);

        var url = $"/v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m,relative_humidity_2m";

        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(
            await response.Content.ReadAsStreamAsync(cancellationToken), cancellationToken: cancellationToken);

        var current = doc.RootElement.GetProperty("current");

        return $"Temperature: {current.GetProperty("temperature_2m")}°C, "
             + $"Wind: {current.GetProperty("wind_speed_10m")} km/h, "
             + $"Humidity: {current.GetProperty("relative_humidity_2m")}%";
    }

    [McpServerTool(ReadOnly = true), Description("Get the daily high and low temperatures for the next 7 days.")]
    public async Task<string> GetWeeklyForecast(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        CancellationToken cancellationToken = default)
    {
        var url = $"/v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&daily=temperature_2m_max,temperature_2m_min&forecast_days=7";

        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }
}

